+
+    /// Query the graph synchronously
+    ///
+    /// # Example
+    /// ```javascript
+    /// const results = db.querySync('MATCH (n) RETURN n LIMIT 10');
+    /// ```
+    #[napi]
+    pub fn query_sync(&self, cypher: String) -> Result<JsQueryResult> {
